Here's a solid pattern using `MockHttpMessageHandler` and MSTest's async support:

```csharp
[TestClass]
public class DataFetcherTests
{
    private static HttpClient CreateClient(Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> handler)
    {
        return new HttpClient(new MockHandler(handler));
    }

    // Happy path
    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        using var client = CreateClient((_, _) =>
            Task.FromResult(new HttpResponseMessage(HttpStatusCode.OK)
            {
                Content = new StringContent("hello")
            }));

        var fetcher = new DataFetcher(client);
        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    // Cancellation: token cancelled before the request completes
    [TestMethod]
    public async Task FetchAsync_ThrowsOperationCanceled_WhenTokenCancelled()
    {
        using var cts = new CancellationTokenSource();

        using var client = CreateClient((_, ct) =>
        {
            cts.Cancel();               // simulate caller cancelling mid-request
            ct.ThrowIfCancellationRequested();
            return Task.FromResult(new HttpResponseMessage());
        });

        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<OperationCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Timeout via CancellationTokenSource.CancelAfter
    [TestMethod]
    public async Task FetchAsync_ThrowsOnTimeout()
    {
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        using var client = CreateClient(async (_, ct) =>
        {
            await Task.Delay(TimeSpan.FromSeconds(10), ct);   // simulate slow server
            return new HttpResponseMessage();
        });

        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Non-success status code
    [TestMethod]
    public async Task FetchAsync_ThrowsHttpRequestException_OnErrorStatus()
    {
        using var client = CreateClient((_, _) =>
            Task.FromResult(new HttpResponseMessage(HttpStatusCode.InternalServerError)));

        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    // Minimal mock handler
    private sealed class MockHandler : HttpMessageHandler
    {
        private readonly Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> _send;
        public MockHandler(Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> send)
            => _send = send;

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
            => _send(request, cancellationToken);
    }
}
```

**Key points:**

- **No mocking library needed** — `MockHandler` overrides `HttpMessageHandler.SendAsync`, which is what `HttpClient` calls internally.
- **Timeout** — use `CancellationTokenSource(TimeSpan)` to create a self-cancelling token; the handler's `Task.Delay` simulates a slow server.
- **Cancellation** — cancel the `CancellationTokenSource` inside the handler to simulate mid-flight cancellation.
- **Always `using`** on `HttpClient` and `CancellationTokenSource` to avoid leaks.
- MSTest runs `async Task` test methods natively — no special config needed.
